                    itemNumber: "CHRMO-AV-001",
                    positionTitle: "Administrative Officer V",
                    salaryGrade: 18,
                    departmentId: hrDept.id,
                    department: hrDept.name,
                    isVacant: true
                }
            ]);
            console.log('Seeded HR High-Level Positions for Setup Portal.');
        }

