    });

    console.warn(`Saved application from ${email} for job ${jobId || 'General'}`);

    let jobTitle = 'General Application';
      
    if (jobId) {
      const job = await db.query.recruitmentJobs.findFirst({
        where: eq(recruitmentJobs.id, Number(jobId)),
